/**
 * Grobase BaaS client — replaces the NestJS+Supabase backend with the local
 * Grobase gateway. Speaks GoTrue (/auth/v1) for identity and the owner-scoped
 * query API (/query/v1/<dbId>/tables/<table>) for CRUD. Unlike a single-tenant
 * app key, vite-gourmand is OWNER-SCOPED: the user's Bearer JWT is forwarded so
 * the data plane stamps/filters owner_id = user:<sub>. Config comes from
 * window.__BAAS__ (public/baas-config.js, machine-generated by gourmand-baas.sh)
 * or import.meta.env.VITE_BAAS_* (a plain `vite build`).
 */

export type BaasConfig = {
  url: string;
  anonKey: string;
  apiKey: string;
  tenantId: string;
  pgDbId: string;
  mongoDbId: string;
  realtimeToken: string;
};

export type Row = Record<string, unknown>;
export type Where = Record<string, unknown>;
export type Sort = Record<string, 'asc' | 'desc'>;
export type ListOptions = { where?: Where; limit?: number; offset?: number; sort?: Sort };
export type QueryResult = { rows: Row[]; rowCount: number };

export type SessionUser = { id: string; email: string; name: string; role: string };
export type Session = { accessToken: string; refreshToken: string; user: SessionUser | null };

type GlobalBaas = { __BAAS__?: Partial<BaasConfig> };

const SESSION_KEY = 'vg.session';

function isRecord(v: unknown): v is Record<string, unknown> {
  return typeof v === 'object' && v !== null;
}

function asString(v: unknown): string {
  return typeof v === 'string' ? v : '';
}

/** Resolve config: window.__BAAS__ (runtime) wins over VITE_BAAS_* (build-time). */
function readConfig(): BaasConfig {
  const w = (typeof window !== 'undefined' ? (window as unknown as GlobalBaas).__BAAS__ : undefined) ?? {};
  const env = import.meta.env;
  return {
    url: w.url ?? env.VITE_BAAS_URL ?? 'http://127.0.0.1:8000',
    anonKey: w.anonKey ?? env.VITE_BAAS_KONG_KEY ?? '',
    apiKey: w.apiKey ?? env.VITE_BAAS_API_KEY ?? '',
    tenantId: w.tenantId ?? env.VITE_BAAS_TENANT_ID ?? 'gourmand',
    pgDbId: w.pgDbId ?? env.VITE_BAAS_PG_DB_ID ?? '',
    mongoDbId: w.mongoDbId ?? env.VITE_BAAS_MONGO_DB_ID ?? '',
    realtimeToken: w.realtimeToken ?? env.VITE_BAAS_REALTIME_TOKEN ?? '',
  };
}

export const config: BaasConfig = readConfig();

// ── session (localStorage-backed GoTrue JWT) ────────────────────────────────

export function loadSession(): Session | null {
  try {
    const raw = localStorage.getItem(SESSION_KEY);
    return raw ? (JSON.parse(raw) as Session) : null;
  } catch {
    return null;
  }
}

function saveSession(session: Session): void {
  try {
    localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  } catch {
    // storage may be unavailable in locked-down contexts
  }
}

export function clearSession(): void {
  try {
    localStorage.removeItem(SESSION_KEY);
  } catch {
    // ignore
  }
}

export function accessToken(): string {
  return loadSession()?.accessToken ?? '';
}

export function isAuthed(): boolean {
  return Boolean(accessToken());
}

/** Decode {id,email,name,role} from a GoTrue JWT payload (no verification). */
function decodeUser(token: string): SessionUser | null {
  try {
    const part = token.split('.')[1].replace(/-/g, '+').replace(/_/g, '/');
    const claims: unknown = JSON.parse(atob(part));
    if (!isRecord(claims)) return null;
    const meta = isRecord(claims.user_metadata) ? claims.user_metadata : {};
    const appMeta = isRecord(claims.app_metadata) ? claims.app_metadata : {};
    return {
      id: asString(claims.sub),
      email: asString(claims.email),
      name: asString(meta.username) || asString(claims.email).split('@')[0],
      role: asString(appMeta.role) || asString(claims.role) || 'customer',
    };
  } catch {
    return null;
  }
}

// ── auth (GoTrue /auth/v1) ──────────────────────────────────────────────────

export class AuthError extends Error {
  readonly code: string;
  constructor(message: string, code: string) {
    super(message);
    this.name = 'AuthError';
    this.code = code;
  }
}

async function authPost(path: string, payload: unknown, token?: string): Promise<Record<string, unknown>> {
  const headers: Record<string, string> = { apikey: config.anonKey, 'Content-Type': 'application/json' };
  if (token) headers.Authorization = `Bearer ${token}`;
  const res = await fetch(`${config.url}/auth/v1${path}`, {
    method: 'POST',
    headers,
    body: JSON.stringify(payload),
  });
  const body: unknown = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg = isRecord(body) ? asString(body.error_description || body.msg || body.message || body.error) : '';
    const code = isRecord(body) ? asString(body.error_code || body.error) : 'unknown';
    throw new AuthError(msg || `auth ${path} failed (${res.status})`, code || 'unknown');
  }
  return isRecord(body) ? body : {};
}

function persist(resp: Record<string, unknown>): SessionUser | null {
  const token = asString(resp.access_token);
  if (!token) return null;
  const user = decodeUser(token);
  saveSession({ accessToken: token, refreshToken: asString(resp.refresh_token), user });
  return user;
}

export const auth = {
  signUp: (i: { email: string; password: string; username?: string }) =>
    authPost('/signup', { email: i.email, password: i.password, data: { username: i.username } }).then(persist),
  signIn: (i: { email: string; password: string }) =>
    authPost('/token?grant_type=password', { email: i.email, password: i.password }).then(persist),
  recover: (email: string) => authPost('/recover', { email }).then(() => undefined),
  async signOut(): Promise<void> {
    const token = accessToken();
    if (token) await authPost('/logout', {}, token).catch(() => undefined);
    clearSession();
  },
  currentUser: (): SessionUser | null => loadSession()?.user ?? null,
};

// ── filters + db (owner-scoped query API) ───────────────────────────────────

/** Lower a {col: value} map to the data plane's {col:{$eq:value}} filter shape. */
export function eqFilter(where: Where): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(where)) out[k] = { $eq: v };
  return out;
}

function dbHeaders(appKeyOnly = false): Record<string, string> {
  const headers: Record<string, string> = {
    apikey: config.anonKey,
    'X-Baas-Api-Key': config.apiKey,
    'Content-Type': 'application/json',
  };
  // appKeyOnly: omit the user JWT so the call owner-scopes to the APP KEY (the
  // identity that owns every seeded/admin row) — used by the admin DB browser so
  // it sees all data across owners, incl. the app-key-owned Mongo analytics.
  const token = accessToken();
  if (token && !appKeyOnly) headers.Authorization = `Bearer ${token}`;
  return headers;
}

function toResult(body: unknown): QueryResult {
  if (!isRecord(body)) return { rows: [], rowCount: 0 };
  const rows = Array.isArray(body.rows) ? body.rows.filter(isRecord) : [];
  const rowCount = typeof body.rowCount === 'number' ? body.rowCount : rows.length;
  return { rows, rowCount };
}

export class BaasError extends Error {
  readonly status: number;
  constructor(status: number, message: string) {
    super(message);
    this.name = 'BaasError';
    this.status = status;
  }
}

async function dbCall(dbId: string, table: string, payload: Record<string, unknown>, appKeyOnly = false): Promise<QueryResult> {
  const res = await fetch(`${config.url}/query/v1/${dbId}/tables/${table}`, {
    method: 'POST',
    headers: dbHeaders(appKeyOnly),
    body: JSON.stringify(payload),
  });
  const body: unknown = await res.json().catch(() => ({}));
  if (!res.ok) {
    const msg = isRecord(body) ? asString(body.message || body.error) : '';
    throw new BaasError(res.status, msg || `query ${table} failed (${res.status})`);
  }
  return toResult(body);
}

export type Db = {
  list: (table: string, opts?: ListOptions) => Promise<QueryResult>;
  get: (table: string, where: Where) => Promise<Row | null>;
  insert: (table: string, data: Row) => Promise<Row | null>;
  update: (table: string, data: Row, where: Where) => Promise<Row | null>;
  remove: (table: string, where: Where) => Promise<QueryResult>;
  count: (table: string, where?: Where) => Promise<number>;
};

/** A CRUD client bound to one mount (dbId) — PG or Mongo. `appKeyOnly` drops the
 *  user JWT so reads/writes own-scope to the app key (the admin DB browser). */
export function makeDb(dbId: string, appKeyOnly = false): Db {
  return {
    list: (table, opts = {}) => {
      const payload: Record<string, unknown> = { op: 'list', filter: eqFilter(opts.where ?? {}) };
      if (opts.limit) payload.limit = opts.limit;
      if (opts.offset) payload.offset = opts.offset;
      if (opts.sort) payload.sort = opts.sort;
      return dbCall(dbId, table, payload, appKeyOnly);
    },
    get: (table, where) => dbCall(dbId, table, { op: 'list', filter: eqFilter(where), limit: 1 }, appKeyOnly).then((r) => r.rows[0] ?? null),
    insert: (table, data) => dbCall(dbId, table, { op: 'insert', data }, appKeyOnly).then((r) => r.rows[0] ?? null),
    update: (table, data, where) => dbCall(dbId, table, { op: 'update', data, filter: eqFilter(where) }, appKeyOnly).then((r) => r.rows[0] ?? null),
    remove: (table, where) => dbCall(dbId, table, { op: 'delete', filter: eqFilter(where) }, appKeyOnly),
    count: (table, where = {}) =>
      dbCall(dbId, table, { op: 'aggregate', filter: eqFilter(where), aggregate: { aggregates: [{ func: 'count', alias: 'n' }] } }, appKeyOnly)
        .then((r) => asNum(r.rows[0]?.n)).catch(() => 0),
  };
}

const asNum = (v: unknown): number => (typeof v === 'number' ? v : Number(v) || 0);

export const db: Db = makeDb(config.pgDbId);
export const mongoDb: Db | null = config.mongoDbId ? makeDb(config.mongoDbId) : null;
// Admin DB-browser clients. PG: keep the admin user's Bearer (a superadmin) so the
// data plane's admin-bypass (F2) lets it read/edit across owners. Mongo: app-key
// identity (the engine owns the analytics docs; Mongo has no admin-bypass yet).
export const adminDb: Db = makeDb(config.pgDbId, false);
export const adminMongoDb: Db | null = config.mongoDbId ? makeDb(config.mongoDbId, true) : null;
export const hasMongo = (): boolean => Boolean(config.mongoDbId);

/** Schema introspection for a mount: `{ tables: [{ name, primary_key, columns:[…] }] }`. */
export async function getSchema(dbId: string): Promise<{ tables: Array<{ name: string; primary_key: string[]; columns: Array<Record<string, unknown>> }> }> {
  const res = await fetch(`${config.url}/query/v1/${dbId}/schema`, { headers: dbHeaders() });
  const body: unknown = await res.json().catch(() => ({}));
  if (!res.ok || !isRecord(body)) return { tables: [] };
  const tables = Array.isArray(body.tables) ? (body.tables as Array<{ name: string; primary_key: string[]; columns: Array<Record<string, unknown>> }>) : [];
  return { tables };
}

// ── realtime (Grobase agnostic-realtime, WebSocket) ─────────────────────────
//
// Writes through /query/v1 publish `row_changed` on topic `table:<dbId>:<table>`.
// Protocol: AUTH → AUTH_OK → SUBSCRIBE{sub_id,topic} → SUBSCRIBED → EVENT.

export type RowChange = {
  event: 'insert' | 'update' | 'delete' | 'change';
  pk: string | number | null;
  table: string;
  ts?: unknown;
};

/** Map a wire EVENT envelope to a flat change. The realtime payload is a
 *  CHANGE NOTIFICATION (`{op,table,pk,filter}`) — NOT the row — so callers
 *  re-fetch the row by `pk` for updates and remove by `pk` for deletes. */
function normalizeChange(msg: Record<string, unknown>): RowChange {
  const e = (isRecord(msg.event) ? msg.event : msg) as Record<string, unknown>;
  const p = (isRecord(e.payload) ? e.payload : isRecord(e.data) ? e.data : e) as Record<string, unknown>;
  const t = asString(p.op || e.event_type || e.event || e.operation || 'change').toLowerCase();
  const event = t.includes('insert') || t.includes('create') ? 'insert'
    : t.includes('update') ? 'update'
    : t.includes('delete') || t.includes('remove') ? 'delete' : 'change';
  const raw = p.pk ?? p.id ?? p._id ?? null;
  const pk = raw === null || typeof raw === 'string' || typeof raw === 'number' ? raw : null;
  return { event, pk, table: asString(p.table), ts: e.timestamp ?? p.ts };
}

/** Subscribe to live row changes for `<dbId>/<table>`; returns an unsubscribe fn.
 *  Auto-reconnects with backoff so the stream survives a dropped socket. */
export function subscribeTable(dbId: string, table: string, onChange: (c: RowChange) => void): () => void {
  if (!dbId || !config.realtimeToken) return () => {};
  const topic = `table:${dbId}:${table}`;
  const subId = `${table}:${dbId.slice(0, 8)}`;
  let ws: WebSocket | null = null;
  let closed = false;
  let retry = 0;

  const connect = () => {
    if (closed) return;
    const proto = config.url.startsWith('https') ? 'wss' : 'ws';
    const base = config.url.replace(/^https?:/, `${proto}:`) || `${proto}://${location.host}`;
    const url = `${base}/realtime/v1/ws?apikey=${encodeURIComponent(config.anonKey)}&access_token=${encodeURIComponent(config.realtimeToken)}`;
    ws = new WebSocket(url);
    ws.addEventListener('open', () => { retry = 0; ws?.send(JSON.stringify({ type: 'AUTH', token: config.realtimeToken })); });
    ws.addEventListener('message', (frame: MessageEvent<string>) => {
      let msg: unknown;
      try { msg = JSON.parse(frame.data); } catch { return; }
      if (!isRecord(msg)) return;
      if (msg.type === 'AUTH_OK') ws?.send(JSON.stringify({ type: 'SUBSCRIBE', sub_id: subId, topic }));
      else if (msg.type === 'EVENT' || msg.type === 'ROW_CHANGED') onChange(normalizeChange(msg));
    });
    ws.addEventListener('close', () => {
      if (closed) return;
      retry = Math.min(retry + 1, 6);
      setTimeout(connect, 500 * retry); // backoff up to 3s
    });
    ws.addEventListener('error', () => ws?.close());
  };
  connect();
  return () => { closed = true; ws?.close(); };
}
